/* Layout: theme-page-layout */
/* Scope: theme */
/* Generated by Layout Maker — do not edit manually */

/* ── Layout frame ── */
.layout-frame {
  width: 100%;
}

/* ── Grid: desktop (1440px+) ── */
.layout-grid {
  display: grid;
  grid-template-columns: 360px 711px 360px;
}

/* ── Slot: header ── */
[data-slot="header"] {
  display: flex;
  flex-direction: column;
  position: sticky;
  top: 0;
  z-index: 100;
}

/* ── Slot: content ── */
[data-slot="content"] {
  display: flex;
  flex-direction: column;
  min-height: 600px;
}

/* ── Slot: theme-blocks ── */
[data-slot="theme-blocks"] {
  display: flex;
  flex-direction: column;
}

/* ── Slot: footer ── */
[data-slot="footer"] {
  display: flex;
  flex-direction: column;
  min-height: 120px;
  margin-top: 32px;
}

/* ── Slot: sidebar-left ── */
[data-slot="sidebar-left"] {
  display: flex;
  flex-direction: column;
  min-height: 400px;
}

/* ── Slot: sidebar-right ── */
[data-slot="sidebar-right"] {
  display: flex;
  flex-direction: column;
  min-height: 400px;
}

/* ── Slot inner vars (base) ── */
:root {
  --sl-header-gap: 24px;
  --sl-content-pt: 24px;
  --sl-content-pb: 24px;
  --sl-theme-blocks-mw: 615px;
  --sl-theme-blocks-gap: 32px;
  --sl-theme-blocks-al: center;
  --sl-footer-gap: 24px;
  --sl-sidebar-left-mw: 360px;
  --sl-sidebar-left-gap: 24px;
  --sl-sidebar-left-pt: 24px;
  --sl-sidebar-left-pb: 24px;
  --sl-sidebar-left-al: center;
  --sl-sidebar-right-mw: 360px;
  --sl-sidebar-right-gap: 24px;
  --sl-sidebar-right-pt: 24px;
  --sl-sidebar-right-pb: 24px;
  --sl-sidebar-right-al: center;
}

[data-slot] > .slot-inner {
  display: flex;
  flex-direction: column;
  width: 100%;
  flex: 1 0 auto;
}

[data-slot="header"] > .slot-inner {
  max-width: var(--sl-header-mw, none);
  padding: var(--sl-header-pt, 0) var(--sl-header-px, 0) var(--sl-header-pb, 0);
  gap: var(--sl-header-gap, 0);
  align-self: var(--sl-header-al, stretch);
  margin-inline: auto;
}

[data-slot="theme-blocks"] > .slot-inner {
  max-width: var(--sl-theme-blocks-mw, none);
  padding: var(--sl-theme-blocks-pt, 0) var(--sl-theme-blocks-px, 0) var(--sl-theme-blocks-pb, 0);
  gap: var(--sl-theme-blocks-gap, 0);
  align-self: var(--sl-theme-blocks-al, stretch);
  margin-inline: auto;
}

[data-slot="footer"] > .slot-inner {
  max-width: var(--sl-footer-mw, none);
  padding: var(--sl-footer-pt, 0) var(--sl-footer-px, 0) var(--sl-footer-pb, 0);
  gap: var(--sl-footer-gap, 0);
  align-self: var(--sl-footer-al, stretch);
  margin-inline: auto;
}

[data-slot="sidebar-left"] > .slot-inner {
  max-width: var(--sl-sidebar-left-mw, none);
  padding: var(--sl-sidebar-left-pt, 0) var(--sl-sidebar-left-px, 0) var(--sl-sidebar-left-pb, 0);
  gap: var(--sl-sidebar-left-gap, 0);
  align-self: var(--sl-sidebar-left-al, stretch);
  margin-inline: auto;
}

[data-slot="sidebar-right"] > .slot-inner {
  max-width: var(--sl-sidebar-right-mw, none);
  padding: var(--sl-sidebar-right-pt, 0) var(--sl-sidebar-right-px, 0) var(--sl-sidebar-right-pb, 0);
  gap: var(--sl-sidebar-right-gap, 0);
  align-self: var(--sl-sidebar-right-al, stretch);
  margin-inline: auto;
}

/* ── Drawer ── */
.layout-drawer {
  position: fixed;
  top: 0;
  left: 0;
  height: 100vh;
  width: 280px;
  background: white;
  z-index: 1000;
  transform: translateX(-100%);
  transition: transform 0.3s ease;
  overflow-y: auto;
}

.layout-drawer--right {
  right: 0;
  left: auto;
  transform: translateX(100%);
}

.layout-drawer.open {
  transform: translateX(0);
}

.layout-drawer-backdrop {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.4);
  z-index: 999;
  opacity: 0;
  pointer-events: none;
  transition: opacity 0.3s ease;
}

.layout-drawer-backdrop.open {
  opacity: 1;
  pointer-events: auto;
}

.drawer-close {
  position: absolute;
  top: 8px;
  right: 8px;
  background: none;
  border: none;
  font-size: 24px;
  cursor: pointer;
  padding: 4px 8px;
}

.drawer-trigger {
  display: none;
  position: fixed;
  top: 50%;
  transform: translateY(-50%);
  z-index: 998;
  background: white;
  border: 1px solid #ddd;
  padding: 8px;
  cursor: pointer;
  border-radius: 4px;
}

.drawer-trigger--left {
  left: 8px;
}

.drawer-trigger--right {
  right: 8px;
}

/* ── Grid: tablet (1400px – 1439px) ── */
@media (max-width: 1439px) {
  .layout-grid {
    grid-template-columns: 1fr;
    column-gap: 0;
  }

  [data-slot="sidebar-left"],
  [data-slot="sidebar-right"] {
    display: none;
  }

  .drawer-trigger {
    display: block;
  }

  .layout-drawer {
    width: 280px;
  }
}
